  description: string;
  completed: boolean;
  completedAt?: string;
}

/**
 * Goal object
 */
export interface Goal {
  id: string;
  title: string;
  description: string;
  status: GoalStatus;
  priority: GoalPriority;
  createdAt: string;
  completedAt?: string;
  deferralReason?: string;
  completionCriteria: CompletionCriterion[];
  // Link to LTM insights
